const rows = $input.all();
const config = {};
for (const r of rows) config[r.json.key] = r.json.value;
return [{ json: { config } }];

const claim = $input.first().json;
const config = $('Build Config Map').first().json.config;

const prompt = `You are a supply chain investigator building a LEGAL CASE that the following claim is TRUE.

CLAIM: ${claim.subject} ${claim.predicate} ${claim.object}
EVIDENCE: "${claim.raw_text || 'No direct evidence — infer from industry knowledge'}"
SOURCE: ${claim.source_url || 'unknown'}

Your job: argue aggressively that this supply chain relationship EXISTS and is real.
Use the evidence. Infer from industry knowledge. Be specific and concrete.

Return ONLY valid JSON:
{"verdict": "TRUE", "points": ["Point 1...", "Point 2...", "Point 3..."], "confidence_delta": 0.25}

confidence_delta must be between 0.10 and 0.45.`;

return [{ json: { claim_id: claim.id, claim, prompt, config } }];

const resp = $input.first().json;
const ctx = $('Build Prosecution Prompt').first().json;

let prosecution = { verdict: 'TRUE', points: [], confidence_delta: 0.2 };
try {
  let content = resp?.choices?.[0]?.message?.content || '{}';
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  prosecution = JSON.parse(content);
} catch(e) {}

if (!prosecution.points) prosecution.points = [];
if (!prosecution.confidence_delta) prosecution.confidence_delta = 0.2;

const claim = ctx.claim;
const config = ctx.config;
const prompt = `You are a supply chain defense attorney challenging the following claim.\n\nCLAIM: ${claim.subject} ${claim.predicate} ${claim.object}\nORIGINAL EVIDENCE: "${claim.raw_text || 'none'}"\nSOURCE: ${claim.source_url || 'unknown'}\n\nPROSECUTION ARGUED:\n${prosecution.points.map((p, i) => `${i+1}. ${p}`).join('\n')}\n\nYour job: argue aggressively that this claim is UNCERTAIN, WRONG, or MISLEADING.\nFind gaps. Challenge source reliability. Identify alternative explanations.\n\nReturn ONLY valid JSON:\n{"verdict": "FALSE", "points": ["Counter 1...", "Counter 2...", "Counter 3..."], "confidence_delta": -0.15}\n\nconfidence_delta must be negative, between -0.40 and -0.05.`;

return [{ json: { claim_id: ctx.claim_id, claim, prosecution, prompt, config } }];

const resp = $input.first().json;
const ctx = $('Parse + Build Defense Prompt').first().json;

let defense = { verdict: 'FALSE', points: [], confidence_delta: -0.15 };
try {
  let content = resp?.choices?.[0]?.message?.content || '{}';
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  defense = JSON.parse(content);
} catch(e) {}

if (!defense.points) defense.points = [];
if (!defense.confidence_delta) defense.confidence_delta = -0.15;

const prosecution = ctx.prosecution;
const claim = ctx.claim;
const config = ctx.config;
const after_prosecution = (0.5 + prosecution.confidence_delta).toFixed(2);
const final_est = (0.5 + prosecution.confidence_delta + defense.confidence_delta).toFixed(2);

const prompt = `You are a senior supply chain analyst. Deliver a final verdict.

CLAIM: ${claim.subject} ${claim.predicate} ${claim.object}
ORIGINAL EVIDENCE: "${claim.raw_text || 'none'}"

PROSECUTION (arguing TRUE):
${prosecution.points.map((p, i) => `${i+1}. ${p}`).join('
')}
Prosecution confidence boost: +${prosecution.confidence_delta}

DEFENSE (arguing FALSE):
${defense.points.map((p, i) => `${i+1}. ${p}`).join('
')}
Defense confidence reduction: ${defense.confidence_delta}

Base: 0.50 + ${prosecution.confidence_delta} - ${Math.abs(defense.confidence_delta)} = ${final_est} (estimate)

Synthesize both sides. Consider source reliability, specificity, corroboration.

Return ONLY valid JSON:
{"confidence": 0.73, "verdict": "ACCEPTED", "contested": false, "reasoning": "One sentence.", "validation_status": "accepted"}

verdict: ACCEPTED (>=0.60), NEEDS_REVIEW (0.40-0.59), REJECTED (<0.40)
validation_status: accepted / needs_review / rejected
contested: true if prosecution and defense strongly disagreed`;

return [{ json: { claim_id: ctx.claim_id, claim, prosecution, defense, prompt, config } }];

const resp = $input.first().json;
const ctx = $('Parse + Build Judge Prompt').first().json;

let verdict = { confidence: 0.5, verdict: 'NEEDS_REVIEW', contested: true, reasoning: 'parse error', validation_status: 'needs_review' };
try {
  let content = resp?.choices?.[0]?.message?.content || '{}';
  // DeepSeek R1 may wrap in <think>...</think>
  content = content.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  verdict = JSON.parse(content);
} catch(e) {}

const confidence = parseFloat(verdict.confidence) || 0.5;
const validation_status = verdict.validation_status || (confidence >= 0.6 ? 'accepted' : confidence >= 0.4 ? 'needs_review' : 'rejected');

return [{ json: {
  claim_id: ctx.claim_id,
  confidence,
  contested: verdict.contested || false,
  reasoning: verdict.reasoning || '',
  validation_status,
  prosecution: ctx.prosecution,
  defense: ctx.defense
} }];
